const express = require('express');
const multer = require('multer');
const path = require('path');
const fs = require('fs');
const sharp = require('sharp');
const fileType = require('file-type');
const app = express();

const uploadDir = path.join(__dirname, 'uploads');
const publicDir = path.join(__dirname, 'public/uploads');

if (!fs.existsSync(uploadDir)) fs.mkdirSync(uploadDir);
if (!fs.existsSync(publicDir)) fs.mkdirSync(publicDir);

const storage = multer.diskStorage({
  destination: (req, file, cb) => {
    cb(null, uploadDir);
  },
  filename: (req, file, cb) => {
    const uniqueSuffix = Date.now() + '-' + Math.round(Math.random() * 1E9);
    cb(null, uniqueSuffix + path.extname(file.originalname));
  }
});

const fileFilter = async (req, file, cb) => {
  const allowedMimeTypes = [
    'image/jpeg', 'image/png', 'image/gif', 'image/svg+xml',
    'application/pdf', 'application/msword',
    'application/vnd.openxmlformats-officedocument.wordprocessingml.document',
    'application/zip'
  ];

  const buffer = await file.stream.read();
  const type = await fileType.fromBuffer(buffer);

  if (type && allowedMimeTypes.includes(type.mime)) {
    cb(null, true);
  } else {
    cb(new Error('Invalid file type'), false);
  }
};

const upload = multer({
  storage: storage,
  fileFilter: fileFilter,
  limits: { fileSize: 50 * 1024 * 1024 } // 50MB limit for non-enterprise users
});

app.post('/upload', upload.single('file'), async (req, res) => {
  try {
    const filePath = path.join(uploadDir, req.file.filename);
    const publicPath = path.join(publicDir, req.file.filename);

    if (req.file.mimetype.startsWith('image/')) {
      await sharp(filePath)
        .resize(100, 100)
        .toFile(publicPath);
    } else {
      fs.copyFileSync(filePath, publicPath);
    }

    res.status(200).json({ message: 'File uploaded successfully', path: `/uploads/${req.file.filename}` });
  } catch (error) {
    res.status(500).json({ error: error.message });
  }
});

app.listen(3000, () => {
  console.log('Server started on http://localhost:3000');
});